def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_distance(point1, point2):
        return np.linalg.norm(point1 - point2)

    def time_window_adjustment(time_window, current_time):
        return max(time_window[0] - current_time, 0) + 0.3 * max(current_time - time_window[1], 0)

    # Initialize variables for best node selection
    best_node = None
    best_score = float('inf')

    # Compute overall fleet centroid to estimate dispersion
    fleet_centroid = np.mean(all_truck_pos, axis=0)
    dispersion_factor = calculate_distance(cur_truck_pos, fleet_centroid)

    for i, customer_pos in enumerate(unvisited_customers):
        travel_time = calculate_distance(cur_truck_pos, customer_pos) / truck_speed
        arrival_time = current_time + travel_time
        window_penalty = time_window_adjustment(time_windows[i], arrival_time)

        wait_time = max(time_windows[i][0] - arrival_time, 0)
        total_time_cost = travel_time + wait_time + window_penalty

        score = total_time_cost + 0.05 * dispersion_factor  # Incorporating dispersion to balance fleet workload

        if score < best_score:
            best_score = score
            best_node = i

    return best_node

import numpy as np
import itertools

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_travel_time(point1, point2):
        return np.linalg.norm(point2 - point1) / truck_speed

    def calculate_time_window_score(arrival_time, window_start, window_end):
        if arrival_time < window_start:
            return (window_start - arrival_time) # Early arrival cost
        elif arrival_time > window_end:
            return float('inf') # Late arrival huge penalty
        return 0 # Perfect timing, no penalty

    best_node = None
    best_score = float('inf')

    # Advanced congestion modeling and delay policy
    def predict_future_congestion(current_pos, future_time):
        return sum(np.exp(-(future_time - (current_time + calculate_travel_time(pos, current_pos)))**2) for pos in all_truck_pos if current_time + calculate_travel_time(pos, current_pos) <= future_time)

    for i, customer_pos in enumerate(unvisited_customers):
        travel_time = calculate_travel_time(cur_truck_pos, customer_pos)
        arrival_time = current_time + travel_time
        window_start, window_end = time_windows[i]

        if arrival_time > window_end:
            continue

        future_congestion = predict_future_congestion(customer_pos, arrival_time)
        time_window_score = calculate_time_window_score(arrival_time, window_start, window_end)
        delay_impact = abs(arrival_time - window_start) * 0.2 if arrival_time < window_start else 0

        score = travel_time + future_congestion * 0.05 + time_window_score + delay_impact

        if score < best_score:
            best_score = score
            best_node = i

    return best_node
